let menuBtn=document.querySelector(".header__btn"),menu=document.querySelector(".home__column-3");function openMenu(e){menuBtn.classList.toggle("header__btn-active"),menu.classList.toggle("home__column-3-active"),document.body.classList.toggle("lock")}menuBtn.addEventListener("click",openMenu);let titles=document.querySelectorAll(".gift__title"),items=document.querySelectorAll(".gift__item");function switchTab(e){e.preventDefault();const t=this.getAttribute("href").replace("#","");titles.forEach(e=>e.classList.remove("gift__title-active")),items.forEach(e=>e.classList.remove("gift__item-active")),this.classList.add("gift__title-active"),document.getElementById(t).classList.add("gift__item-active")}titles.forEach(e=>e.addEventListener("click",switchTab)),$(document).ready((function(){$(".slider").slick({rows:2,slidesToShow:1,infinite:!1,variableWidth:!0,responsive:[{breakpoint:600,settings:{slidesToShow:1,variableWidth:!1}}]}),$(".combo__slider").slick({rows:1,slidesToShow:1,infinite:!1,variableWidth:!0,responsive:[{breakpoint:786,settings:{slidesToShow:1}},{breakpoint:400,settings:{variableWidth:!1}}]})}));